import{_ as a,o as r,c as s,ag as t}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),o={name:"faq.md"};function i(n,e,l,d,c,h){return r(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><h2 id="what-frameworks-are-supported" tabindex="-1">What frameworks are supported? <a class="header-anchor" href="#what-frameworks-are-supported" aria-label="Permalink to &quot;What frameworks are supported?&quot;">​</a></h2><p>Helix Scripts support <strong>ESX</strong>, <strong>QBCore</strong>, and <strong>Qbox</strong> out of the box. The framework bridge in <code>helix_lib</code> auto-detects which framework is running, so you don&#39;t need to configure anything manually. You can also lock to a specific framework in <code>config.lua</code> if you prefer.</p><h2 id="is-helix-lib-required" tabindex="-1">Is helix_lib required? <a class="header-anchor" href="#is-helix-lib-required" aria-label="Permalink to &quot;Is helix_lib required?&quot;">​</a></h2><p><strong>Yes.</strong> <code>helix_lib</code> is the shared library that all Helix scripts depend on. It must be installed and started before any other Helix resource. It is free, open-source, and MIT licensed.</p><div class="language-cfg vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cfg</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># server.cfg — helix_lib must come first</span></span>
<span class="line"><span>ensure helix_lib</span></span>
<span class="line"><span>ensure helix_hud</span></span></code></pre></div><h2 id="what-is-the-performance-impact" tabindex="-1">What is the performance impact? <a class="header-anchor" href="#what-is-the-performance-impact" aria-label="Permalink to &quot;What is the performance impact?&quot;">​</a></h2><p>Helix scripts are designed to be as lightweight as possible. Idle resmon usage sits below <strong>0.01 ms</strong> for all Helix resources. NUI bundles are built with Vite for minimal size and fast load times. We actively benchmark every release to prevent regressions.</p><h2 id="can-i-customise-the-nui" tabindex="-1">Can I customise the NUI? <a class="header-anchor" href="#can-i-customise-the-nui" aria-label="Permalink to &quot;Can I customise the NUI?&quot;">​</a></h2><p>Yes. The NUI layer is built with <strong>React</strong> and uses a design-token system for colours, spacing, and typography. You can override tokens in the resource&#39;s config or fork the NUI source and build your own version with <code>npm run build</code>.</p><h2 id="where-do-i-report-bugs" tabindex="-1">Where do I report bugs? <a class="header-anchor" href="#where-do-i-report-bugs" aria-label="Permalink to &quot;Where do I report bugs?&quot;">​</a></h2><p>Open an issue on the relevant GitHub repository under the <a href="https://github.com/Helix-Scripts" target="_blank" rel="noreferrer">Helix-Scripts organisation</a>. Please include your framework, server artifact version, and any relevant console output.</p><h2 id="is-there-a-discord" tabindex="-1">Is there a Discord? <a class="header-anchor" href="#is-there-a-discord" aria-label="Permalink to &quot;Is there a Discord?&quot;">​</a></h2><p>Yes! Join us at <a href="https://discord.gg/QcAkQ6ZAE6" target="_blank" rel="noreferrer">discord.gg/QcAkQ6ZAE6</a> for support, development updates, and community discussion.</p>`,14)])])}const f=a(o,[["render",i]]);export{p as __pageData,f as default};
